var input = inputs.Length > 0 && inputs[0] != null ? inputs[0]! :
    new PixelBuffer(context.TileSize, context.TileSize);

var seed = GetInt(parameters, "seed", context.Seed);
var channel = GetChoice(parameters, "inputChannel", "luminance");
var colorCount = Math.Clamp(GetInt(parameters, "colorCount", 5), 2, 5);
var dither = GetFloat(parameters, "dither", 0f);
var invert = GetBool(parameters, "invert", false);

// Collect gradient stops
var stopColors = new (float Pos, float R, float G, float B)[colorCount];
var colorNames = new[] { "color0", "color1", "color2", "color3", "color4" };
for (var i = 0; i < colorCount; i++)
{
    var col = GetColor(parameters, colorNames[i], System.Windows.Media.Color.FromRgb(0, 0, 0));
    stopColors[i] = (
        i / (float)(colorCount - 1),
        col.R / 255f, col.G / 255f, col.B / 255f
    );
}

var size = context.TileSize;
var output = new PixelBuffer(size, size);

// Pre-compute dither pattern (Bayer 4x4)
var bayer = new[,]
{
    { 0, 8, 2, 10 },
    { 12, 4, 14, 6 },
    { 3, 11, 1, 9 },
    { 15, 7, 13, 5 }
};

output.ParallelForEachPixel((x, y) =>
{
    var (r, g, b, a) = input.GetPixel(x, y);

    var val = channel switch
    {
        "red" => r,
        "green" => g,
        "blue" => b,
        "alpha" => a,
        _ => r * 0.299f + g * 0.587f + b * 0.114f
    };

    if (invert) val = 1f - val;

    // Dither
    if (dither > 0f)
    {
        var ditherVal = (bayer[y % 4, x % 4] + 0.5f) / 16f - 0.5f;
        val += ditherVal * dither;
        val = Math.Clamp(val, 0f, 1f);
    }

    // Sample gradient
    float outR, outG, outB;
    if (val <= 0f)
    {
        outR = stopColors[0].R;
        outG = stopColors[0].G;
        outB = stopColors[0].B;
    }
    else if (val >= 1f)
    {
        outR = stopColors[colorCount - 1].R;
        outG = stopColors[colorCount - 1].G;
        outB = stopColors[colorCount - 1].B;
    }
    else
    {
        var idx = 0;
        for (var i = 0; i < colorCount - 1; i++)
        {
            if (val >= stopColors[i].Pos && val <= stopColors[i + 1].Pos)
            {
                idx = i;
                break;
            }
        }

        var t = (val - stopColors[idx].Pos) /
                (stopColors[idx + 1].Pos - stopColors[idx].Pos);
        t = Math.Clamp(t, 0f, 1f);

        outR = Lerp(stopColors[idx].R, stopColors[idx + 1].R, t);
        outG = Lerp(stopColors[idx].G, stopColors[idx + 1].G, t);
        outB = Lerp(stopColors[idx].B, stopColors[idx + 1].B, t);
    }

    output.SetPixel(x, y, outR, outG, outB, a);
});

return output;
}
